import{_ as e,a,b as o,c as d,d as n,e as r}from"./chunks/查询额度成功.BKueuYqe.js";import{_ as p,o as i,c as s,a2 as l}from"./chunks/framework.DnrXFDHb.js";const y=JSON.parse('{"title":"Thêm Dropbox Channel","description":"","frontmatter":{},"headers":[],"relativePath":"vi-VN/upload/dropbox.md","filePath":"vi-VN/upload/dropbox.md","lastUpdated":1781962217000}'),c={name:"vi-VN/upload/dropbox.md"};function h(b,t,u,m,g,f){return i(),s("div",null,[...t[0]||(t[0]=[l('<h1 id="them-dropbox-channel" tabindex="-1">Thêm Dropbox Channel <a class="header-anchor" href="#them-dropbox-channel" aria-label="Permalink to &quot;Thêm Dropbox Channel&quot;">​</a></h1><h2 id="can-chuan-bi-truoc" tabindex="-1">Cần chuẩn bị trước <a class="header-anchor" href="#can-chuan-bi-truoc" aria-label="Permalink to &quot;Cần chuẩn bị trước&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Requirement</th><th>Vì sao cần</th></tr></thead><tbody><tr><td>Dropbox account</td><td>Dùng để sign in và authorize app</td></tr><tr><td>Dropbox app</td><td>Dùng để generate <code>App Key</code> và <code>App Secret</code></td></tr><tr><td>ImgBed domain của bạn</td><td>Dùng cho OAuth redirect URI</td></tr><tr><td>Available Dropbox storage</td><td>Dùng làm nơi lưu file thực tế</td></tr></tbody></table><h2 id="cac-buoc-thiet-lap" tabindex="-1">Các bước thiết lập <a class="header-anchor" href="#cac-buoc-thiet-lap" aria-label="Permalink to &quot;Các bước thiết lập&quot;">​</a></h2><h3 id="step-1-tao-dropbox-app" tabindex="-1">Step 1: Tạo Dropbox App <a class="header-anchor" href="#step-1-tao-dropbox-app" aria-label="Permalink to &quot;Step 1: Tạo Dropbox App&quot;">​</a></h3><ol><li>Mở Dropbox App Console:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://www.dropbox.com/developers/apps</span></span></code></pre></div><ol start="2"><li>Tạo app mới.</li><li>Với access type, chọn:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>App folder</span></span></code></pre></div><ol start="4"><li>Đặt tên app dễ nhận biết, ví dụ <code>imgbed-app</code>.</li><li>Mở app details page sau khi tạo xong.</li></ol><p>Recommended access type:</p><table tabindex="0"><thead><tr><th>Access Type</th><th>Recommendation</th></tr></thead><tbody><tr><td><code>App folder</code></td><td>Recommended. Phù hợp với cách ImgBed lưu files.</td></tr><tr><td><code>Full Dropbox</code></td><td>Không recommended. ImgBed không cần access toàn bộ account.</td></tr></tbody></table><p><img src="'+e+'" alt="Create Dropbox app" loading="lazy"></p><h3 id="step-2-them-redirect-uri" tabindex="-1">Step 2: Thêm Redirect URI <a class="header-anchor" href="#step-2-them-redirect-uri" aria-label="Permalink to &quot;Step 2: Thêm Redirect URI&quot;">​</a></h3><p>Trong Dropbox app details page, tìm OAuth hoặc Redirect URI settings và thêm:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/api/oauth/dropbox/callback</span></span></code></pre></div><p>Nếu dùng admin panel từ nhiều domain, thêm từng callback URL tương ứng.</p><p><img src="'+a+'" alt="Configure redirect URI" loading="lazy"></p><h3 id="step-3-configure-app-permissions" tabindex="-1">Step 3: Configure App Permissions <a class="header-anchor" href="#step-3-configure-app-permissions" aria-label="Permalink to &quot;Step 3: Configure App Permissions&quot;">​</a></h3><p>Mở tab <code>Permissions</code> và enable ít nhất các scopes này:</p><table tabindex="0"><thead><tr><th>Scope</th><th>Required</th><th>Purpose</th></tr></thead><tbody><tr><td><code>account_info.read</code></td><td>Required</td><td>Đọc account và quota information</td></tr><tr><td><code>files.metadata.read</code></td><td>Required</td><td>Đọc file và folder metadata để check path</td></tr><tr><td><code>files.metadata.write</code></td><td>Required</td><td>Tạo folders và ghi metadata</td></tr><tr><td><code>files.content.write</code></td><td>Required</td><td>Upload files. Thiếu scope này sẽ gây lỗi <code>required scope &#39;files.content.write&#39;</code>.</td></tr><tr><td><code>files.content.read</code></td><td>Recommended</td><td>Cho phép download, preview và temporary file links</td></tr></tbody></table><p>Sau khi chọn scopes, nhấn <code>Submit</code> ở cuối page.</p><p><img src="'+o+'" alt="Add permissions" loading="lazy"></p><p>Important:</p><table tabindex="0"><thead><tr><th>Situation</th><th>Cần làm gì</th></tr></thead><tbody><tr><td>Bạn đổi scopes</td><td>Chạy lại token authorization flow và lấy <code>Refresh Token</code> mới.</td></tr><tr><td>Bạn chưa reauthorize</td><td>Token cũ sẽ không có permissions mới, nên uploads vẫn có thể fail.</td></tr></tbody></table><h3 id="step-4-copy-app-credentials" tabindex="-1">Step 4: Copy App Credentials <a class="header-anchor" href="#step-4-copy-app-credentials" aria-label="Permalink to &quot;Step 4: Copy App Credentials&quot;">​</a></h3><p>Lưu hai giá trị này từ Dropbox app page:</p><table tabindex="0"><thead><tr><th>Dropbox Field</th><th>ImgBed Field</th></tr></thead><tbody><tr><td><code>App key</code></td><td><code>App Key</code></td></tr><tr><td><code>App secret</code></td><td><code>App Secret</code></td></tr></tbody></table><h3 id="step-5-đien-dropbox-channel" tabindex="-1">Step 5: Điền Dropbox Channel <a class="header-anchor" href="#step-5-đien-dropbox-channel" aria-label="Permalink to &quot;Step 5: Điền Dropbox Channel&quot;">​</a></h3><p>Trong Upload Settings, chọn <code>Dropbox</code> và điền:</p><table tabindex="0"><thead><tr><th>ImgBed Field</th><th>Nhập gì</th></tr></thead><tbody><tr><td>Channel name</td><td>Tên dễ nhận biết, ví dụ <code>Main Dropbox</code></td></tr><tr><td>App Key</td><td>Dropbox <code>App key</code></td></tr><tr><td>App Secret</td><td>Dropbox <code>App secret</code></td></tr><tr><td>Refresh Token</td><td>Tạm thời để trống</td></tr><tr><td>Root directory</td><td>Optional. Mặc định là <code>imgbed</code>.</td></tr><tr><td>Note</td><td>Optional</td></tr></tbody></table><p><img src="'+d+'" alt="Get token" loading="lazy"></p><h3 id="step-6-lay-refresh-token" tabindex="-1">Step 6: Lấy Refresh Token <a class="header-anchor" href="#step-6-lay-refresh-token" aria-label="Permalink to &quot;Step 6: Lấy Refresh Token&quot;">​</a></h3><ol><li>Trong ImgBed, nhấn <code>Get Token</code>.</li><li>Sign in vào Dropbox account bạn muốn kết nối.</li><li>Approve authorization prompt.</li><li>Callback page sẽ hiển thị <code>Refresh Token</code>.</li><li>Copy token đó.</li><li>Quay lại ImgBed và paste vào field <code>Refresh Token</code>.</li></ol><p><img src="'+n+'" alt="Copy token" loading="lazy"></p><h2 id="cach-kiem-tra" tabindex="-1">Cách kiểm tra <a class="header-anchor" href="#cach-kiem-tra" aria-label="Permalink to &quot;Cách kiểm tra&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Check</th><th>Expected Result</th></tr></thead><tbody><tr><td>Channel card</td><td>Dropbox channel xuất hiện sau khi save.</td></tr><tr><td>Channel switch</td><td>Channel có thể enabled.</td></tr><tr><td>Token saved</td><td>Detail page hiển thị <code>Refresh Token</code> đã được lưu.</td></tr><tr><td>Upload test</td><td>Test image xuất hiện trong Dropbox app folder.</td></tr></tbody></table><p>Nếu bật quota limits, nhấn quota query. Sau khi query thành công, channel card sẽ hiển thị used space, total space và last update time.</p><p><img src="'+r+`" alt="Quota query success" loading="lazy"></p><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Problem</th><th>Fix</th></tr></thead><tbody><tr><td>ImgBed báo configuration incomplete</td><td>Kiểm tra <code>App Key</code>, <code>App Secret</code> và <code>Refresh Token</code> đã điền đủ chưa.</td></tr><tr><td>Authorization thành công nhưng không thấy <code>Refresh Token</code></td><td>Nhấn <code>Get Token</code> lại và đảm bảo offline authorization flow được dùng.</td></tr><tr><td>Upload fail với <code>required scope &#39;files.content.write&#39;</code></td><td>Enable <code>files.content.write</code>, nhấn <code>Submit</code>, rồi lấy <code>Refresh Token</code> mới.</td></tr><tr><td>Callback fail</td><td>Xác nhận redirect URI là <code>https://your-domain.com/api/oauth/dropbox/callback</code>.</td></tr><tr><td>Không tìm thấy files</td><td>Xác nhận Dropbox app được tạo ở mode <code>App folder</code>.</td></tr></tbody></table><h2 id="quick-flow" tabindex="-1">Quick Flow <a class="header-anchor" href="#quick-flow" aria-label="Permalink to &quot;Quick Flow&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Mở Dropbox App Console</span></span>
<span class="line"><span>-&gt; Tạo app</span></span>
<span class="line"><span>-&gt; Chọn App folder access</span></span>
<span class="line"><span>-&gt; Thêm https://your-domain.com/api/oauth/dropbox/callback</span></span>
<span class="line"><span>-&gt; Enable account_info.read / files.metadata.read / files.metadata.write / files.content.write</span></span>
<span class="line"><span>-&gt; Có thể enable thêm files.content.read</span></span>
<span class="line"><span>-&gt; Nhấn Submit</span></span>
<span class="line"><span>-&gt; Copy App Key và App Secret</span></span>
<span class="line"><span>-&gt; Điền vào ImgBed</span></span>
<span class="line"><span>-&gt; Nhấn Get Token</span></span>
<span class="line"><span>-&gt; Copy Refresh Token từ callback page</span></span>
<span class="line"><span>-&gt; Paste lại vào ImgBed và save</span></span></code></pre></div><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ol><li>Dropbox App Console: <a href="https://www.dropbox.com/developers/apps" target="_blank" rel="noreferrer">https://www.dropbox.com/developers/apps</a></li><li>Dropbox OAuth Guide: <a href="https://developers.dropbox.com/oauth-guide" target="_blank" rel="noreferrer">https://developers.dropbox.com/oauth-guide</a></li><li>Dropbox Developer Guide: <a href="https://www.dropbox.com/developers/reference/developer-guide" target="_blank" rel="noreferrer">https://www.dropbox.com/developers/reference/developer-guide</a></li></ol>`,45)])])}const v=p(c,[["render",h]]);export{y as __pageData,v as default};
